const ControlledDataTable = () => {
    // Sorting
    const [sortBy, setSortBy] = useState<DataUserKeys>('progress');
    const [sortDirection, setSortDirection] = useState<'ascending' | 'descending'>('descending');
    // Selection
    const [selection, setSelection] = useState<string[]>(['1', '2']);
    // Pagination
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);

    return (
        <DataTable
            enableSelection
            enableSorting
            enablePagination
            data={tableFlat}
            columns={dataColumnsUser}
            primaryKey="id"
            sortBy={sortBy}
            sortDirection={sortDirection}
            selection={selection}
            currentPage={currentPage}
            itemsPerPage={itemsPerPage}
            totalItems={tableFlat.length}
            onSortChange={(newSortBy, newSortDirection) => {
                setSortBy(newSortBy as DataUserKeys);
                setSortDirection(newSortDirection);
            }}
            onChangeSelection={setSelection}
            onPageChange={setCurrentPage}
            onItemsPerPageChange={setItemsPerPage}
        />
    );
};

const InsertCells = () => {
    return (
        <DataTable
            data={tableFlat}
            columns={dataColumnsUser}
            primaryKey="id"
            enableSelection
            renderRow={(row, renderCells) => (
                <TableRow
                    key={row.id}
                >
                    {renderCells({
                        before: (
                            <TableCellStatus color={getStatus(row.original.status).color}>
                                <>
                                    {getStatus(row.original.status).iconStart} {getStatus(row.original.status).text}
                                </>
                            </TableCellStatus>
                        ),
                        after: (
                            <TableCellActions
                                actionsOnHover={
                                    <>
                                        <Button icon={<Visibility/>} variant="ghost"/>
                                        <Button icon={<Edit/>} variant="ghost"/>
                                        <Button icon={<Delete/>} variant="ghost"/>
                                    </>
                                }
                                actions={<Button icon={<MoreVert/>} variant="ghost" aria-label="Actions"/>}
                            />
                        )
                    })}
                </TableRow>
            )} />
    );
};

renderRow.description:
Custom render function for rows (e.g. styling, wrapper).
@param row - The row object from TanStack Table. Use row.original to access the raw row data.
@param render - Function to render the default row content. Accepts options to inject actions per row.

