    const [isDisplayed, setIsDisplayed] = useState<boolean>(false);
    const [menuPosition, setMenuPosition] = useState<AnchorPosition>();

    const handleOnClick = (e: React.MouseEvent) => {
        if (isDisplayed) {
            handleClose();
        } else {
            setIsDisplayed(true);
            setMenuPosition({
