                <MenuItem label="Item3"/>
            </Menu>
        </div>
    );
};

const AnchorElOrigin = () => {
    const [isDisplayed, setIsDisplayed] = useState(false);
    const [anchorEl, setAnchorEl] = useState(null);
    const buttonEl = React.useRef();

    const handleOnClick = () => {
        setAnchorEl(buttonEl);
        if (isDisplayed) {
            handleClose();
        } else {
            setIsDisplayed(true);
        }
    };

    const handleClose = () => {
        setIsDisplayed(false);
